233→        public void InsertMes(
234→            decimal relief_min,
235→            decimal relief_max,
236→            decimal relief_avg,
237→            decimal relief_last,
238→            string relief_decision
239→        )
240→        {
241→            try
242→            {
243→                DateTime now = DateTime.Now;
244→                string work_date = now.ToString("yyyy-MM-dd");
245→                TimeSpan work_start_time = GlobalValues.WorkStartTime != DateTime.MinValue
246→                    ? GlobalValues.WorkStartTime.TimeOfDay
247→                    : now.TimeOfDay;
248→                TimeSpan work_end_time = now.TimeOfDay;
249→
250→                using (var conn = new OleDbConnection(GlobalValues.gConString_MES))
251→                {
252→                    conn.Open();
253→
254→                    string query = @"
255→                INSERT INTO AIR_PUMP_ASSY_340
256→                (
257→                    work_date,
258→                    work_start_time,
259→                    work_end_time,
260→                    relief_min,
261→                    relief_max,
262→                    relief_avg,
263→                    relief_last,
264→                    relief_decision
265→                )
266→                VALUES
267→                (
268→                    ?, ?, ?, ?, ?, ?, ?, ?
269→                )";
270→
271→                    using (var cmd = new OleDbCommand(query, conn))
272→                    {
273→                        cmd.Parameters.AddWithValue("@p1", work_date);
274→                        cmd.Parameters.AddWithValue("@p2", work_start_time.ToString(@"hh\:mm\:ss"));
275→                        cmd.Parameters.AddWithValue("@p3", work_end_time.ToString(@"hh\:mm\:ss"));
276→                        cmd.Parameters.AddWithValue("@p4", relief_min);
277→                        cmd.Parameters.AddWithValue("@p5", relief_max);
278→                        cmd.Parameters.AddWithValue("@p6", relief_avg);
279→                        cmd.Parameters.AddWithValue("@p7", relief_last);
280→                        cmd.Parameters.AddWithValue("@p8", relief_decision ?? (object)DBNull.Value);
281→
282→                        cmd.ExecuteNonQuery();
283→                    }
284→                }
285→
286→                Logger.Log("MES 데이터 삽입 성공");
287→            }
288→            catch (Exception ex)
289→            {
290→                Logger.Log("MES 데이터 삽입 오류: " + ex.Message);
291→            }
292→        }
