304→        private void tmrWorkTimer_Tick(object sender, EventArgs e)
305→        {
306→            srcState.Text = currentState.ToString();
307→            lbBar1.Text = ValAirPress1.ToString() + " bar";
308→            bool[] fioInputs = _fio.FioInput();
309→            // 전압 값 실시간 표시 (이벤트로도 업데이트되지만, 타이머에서도 업데이트)
310→
311→            if (fioInputs[RESET_BUTTON_SIGNAL] == true && wStep != 0)
312→            {
313→                InitControl();
314→                _fio.Fio_Do_Off(L_OUT_SIGNAL);
315→                _fio.Fio_Do_Off(R_OUT_SIGNAL);
316→                wStep = 0;
317→            }
318→            switch (wStep)
319→            {
320→
321→                case 0:
322→
323→                    if (fioInputs[L_IN_BUTTON_SIGNAL] == true)
324→                    {
325→                        InitControl();
326→                        GlobalValues.WorkStartTime = DateTime.Now; // 작업 시작 시간 저장
327→                        FlagButtonRelease = false;
328→                        wStep = 10;
329→                    }
330→                    else if (fioInputs[R_IN_BUTTON_SIGNAL] == true)
331→                    {
332→                        InitControl();
333→                        GlobalValues.WorkStartTime = DateTime.Now; // 작업 시작 시간 저장
334→                        FlagButtonRelease = false;
335→                        wStep = 20;
336→                    }
337→                    break;
338→
339→                case 10:
340→
341→                    _fio.Fio_Do_On(L_OUT_SIGNAL);
342→                    tmrStopWatch.Restart();
343→                    wStep = 11;
344→                    break;
345→
346→                case 11:
347→                    if (tmrStopWatch.Elapsed.TotalSeconds > 1)
348→                    {
349→                        graphValueList.Clear(); // case 12 시작 전 리스트 초기화
350→                        wStep = 12;
351→                    }
352→                    break;
353→
354→                case 12:
355→
356→                    if (fioInputs[L_IN_BUTTON_SIGNAL] == false)
357→                    {
358→                        FlagButtonRelease = true;
359→                    }
360→                    double t = tmrStopWatch.Elapsed.TotalSeconds;
361→                    ClassZedGraph.DrawGraph(GraphL, ValAirPress1, t);
362→
363→                    // 그래프 값 수집 (fioInputs[0] == true 되기 전까지)
364→                    graphValueList.Add(ValAirPress1);
365→
366→                    if (fioInputs[L_IN_BUTTON_SIGNAL] == true && FlagButtonRelease == true)
367→                    {
368→                        _fio.Fio_Do_Off(L_OUT_SIGNAL);
369→                        // 그래프 값의 최대, 최소, 평균 계산하여 필드 변수에 저장
370→                        graphMax = graphValueList.Count > 0 ? graphValueList.Max() : 0.0;
371→                        graphMin = graphValueList.Count > 0 ? graphValueList.Min() : 0.0;
372→                        graphAvg = graphValueList.Count > 0 ? graphValueList.Average() : 0.0;
373→                        graphLast = ValAirPress1;
374→                        wStep = 13;
375→                    }
376→                    break;
377→
378→                case 13:
379→                    // 값 표시
380→                    srclbValMinL.Text = $"{graphMin:F4}";
381→                    srclbValMaxL.Text = $"{graphMax:F4}";
382→                    srclbValAvrL.Text = $"{graphAvg:F4}";
383→                    srclbValLastL.Text = $"{graphLast:F4}";
384→
385→                    // 판정: Avr 값이 범위 내에 있는지 확인
386→                    LastOk = (graphLast >= GlobalValues._1cellAir_Max_Min) && (graphLast <= GlobalValues._1cellAir_Max_Max);
387→                    srclbDecMaxL.Text = LastOk ? "OK" : "NG";
388→                    srclbDecMaxL.ForeColor = LastOk ? Color.Green : Color.Red;
389→                    wStep = 14;
390→                    break;
391→
392→                case 14:                    
393→                    Decision = LastOk ? "OK" : "NG";
394→                    InsertMes(
395→                        (decimal)graphMin,
396→                        (decimal)graphMax,
397→                        (decimal)graphAvg,
398→                        (decimal)graphLast,
399→                        Decision
400→                    );
401→
402→                    wStep = 0;
403→                    break;
404→
405→                case 20:
406→
407→                    _fio.Fio_Do_On(R_OUT_SIGNAL);
408→                    tmrStopWatch.Restart();
409→                    wStep = 21;
410→                    break;
411→
412→                case 21:
413→                    if (tmrStopWatch.Elapsed.TotalSeconds > 1)
414→                    {
415→                        graphValueList.Clear(); // case 22 시작 전 리스트 초기화
416→                        wStep = 22;
417→                    }
418→                    break;
419→
420→                case 22:
421→                    if (fioInputs[R_IN_BUTTON_SIGNAL] == false)
422→                    {
423→                        FlagButtonRelease = true;
424→                    }
425→
426→                    double tR = tmrStopWatch.Elapsed.TotalSeconds;
427→                    ClassZedGraph.DrawGraph(GraphR, ValAirPress1, tR);
428→
429→                    // 그래프 값 수집 (fioInputs[2] == true 되기 전까지)
430→                    graphValueList.Add(ValAirPress1);
431→
432→                    if (fioInputs[R_IN_BUTTON_SIGNAL] == true && FlagButtonRelease == true)
433→                    {
434→                        _fio.Fio_Do_Off(R_OUT_SIGNAL);
435→                        // 그래프 값의 최대, 최소, 평균 계산하여 필드 변수에 저장
436→                        graphMax = graphValueList.Count > 0 ? graphValueList.Max() : 0.0;
437→                        graphMin = graphValueList.Count > 0 ? graphValueList.Min() : 0.0;
438→                        graphAvg = graphValueList.Count > 0 ? graphValueList.Average() : 0.0;
439→                        graphLast = ValAirPress1;
440→                        wStep = 23;
441→                    }
442→                    break;
443→
444→                case 23:
445→                    // 값 표시
446→                    srclbValMinR.Text = $"{graphMin:F4}";
447→                    srclbValMaxR.Text = $"{graphMax:F4}";
448→                    srclbValAvrR.Text = $"{graphAvg:F4}";
449→                    srclbValLastR.Text = $"{graphLast:F4}";
450→
451→                    // 판정: Avr 값이 범위 내에 있는지 확인
452→                    LastOk = (graphLast >= GlobalValues._7cellAir_Max_Min) && (graphLast <= GlobalValues._7cellAir_Max_Max);
453→                    srclbDecMaxR.Text = LastOk ? "OK" : "NG";
454→                    srclbDecMaxR.ForeColor = LastOk ? Color.Green : Color.Red;
455→                    wStep = 24;
456→                    break;
457→
458→                case 24:                    
459→                    Decision = LastOk ? "OK" : "NG";
460→                    InsertMes(
461→                        (decimal)graphMin,
462→                        (decimal)graphMax,
463→                        (decimal)graphAvg,
464→                        (decimal)graphLast,
465→                        Decision
466→                    );
467→
468→                    wStep = 0;
469→                    break;
470→            }
471→        }
