655→        {
656→            try
657→            {
658→                // 기존 인스턴스가 있으면 해제
659→                if (voltageMonitor != null)
660→                {
661→                    voltageMonitor.Stop();
662→                    voltageMonitor.Dispose();
663→                    voltageMonitor = null;
664→                }
665→
666→                // DAQ 채널 설정 (config.ini에서 읽거나 자동 탐지)
667→                IniFile ini = new IniFile("config.ini");
668→                string channel0 = ini.ReadValue("DAQ", "Channel0");
669→                string channel1 = ini.ReadValue("DAQ", "Channel1");
670→
671→                // 연결된 DAQ 장치 자동 탐지 (Dev1부터 Dev10까지 시도)
672→                string deviceName = "Dev1"; // 기본값
673→                if (string.IsNullOrWhiteSpace(channel0))
674→                {
675→                    try
676→                    {
677→                        // 기존 Task 정리 (혹시 남아있을 수 있음)
678→                        try
679→                        {
680→                            using (Task cleanupTask = new Task("DaqTask"))
681→                            {
682→                                cleanupTask.Dispose();
683→                            }
684→                        }
685→                        catch { }
686→
687→                        for (int i = 1; i <= 10; i++)
688→                        {
689→                            string testDevice = $"Dev{i}";
690→                            string testChannel = $"{testDevice}/ai0";
691→                            Task testTask = null;
692→                            try
693→                            {
694→                                testTask = new Task($"AutoDetectTask_{i}");
695→                                testTask.AIChannels.CreateVoltageChannel(
696→                                    testChannel, "Test", AITerminalConfiguration.Differential, -10, 10, AIVoltageUnits.Volts);
697→                                deviceName = testDevice;
698→                                Logger.Log($"DAQ 장치 자동 탐지: {deviceName}");
699→                                testTask.Stop();
700→                                testTask.Dispose();
701→                                testTask = null;
702→                                Thread.Sleep(200); // Task 해제 대기
703→                                break;
704→                            }
705→                            catch
706→                            {
707→                                // 이 장치는 없음, 다음 장치 시도
708→                                if (testTask != null)
709→                                {
710→                                    try { testTask.Dispose(); } catch { }
711→                                }
712→                                continue;
713→                            }
714→                        }
715→                    }
716→                    catch (Exception ex)
717→                    {
718→                        Logger.Log($"DAQ 장치 탐지 실패: {ex.Message}, 기본값 Dev1 사용");
719→                    }
720→                    channel0 = $"{deviceName}/ai0";
721→                }
