        private StringBuilder LoadCellreceiveBuffer = new StringBuilder();
        private int currentRequestAddress = 0;
        private bool currentIsWrite = false;

        private DateTime cycleStartTime = DateTime.Now;
        private int[] lastWriteBuffer = new int[65536]; // 최대 64K 워드 공간

        private VoltageMonitor voltageMonitor;
        private ClassFio _fio;
        private ClassSerialGather SerialAIrPress1;
        private void StyleControls()
        {
            System.Drawing.Color darkBack = ColorTranslator.FromHtml("#1E1E2F");
            System.Drawing.Color darkPanel = ColorTranslator.FromHtml("#2A2A3C");
            System.Drawing.Color mint = ColorTranslator.FromHtml("#00ACC1");
            System.Drawing.Color lightMint = ColorTranslator.FromHtml("#80DEEA");
            System.Drawing.Color softPanelBlue = ColorTranslator.FromHtml("#4DD0E1");
            System.Drawing.Color resultGray = System.Drawing.Color.Gainsboro;

            this.BackColor = darkBack;
            panel4.BackColor = darkPanel;
            panel5.BackColor = darkBack;

            // Label 스타일
            label1.ForeColor = System.Drawing.Color.White;

            // Count 영역 스타일
            lbOkCount.BackColor = lightMint;
            lbNGCount.BackColor = lightMint;
            lbTotalCount.BackColor = lightMint;
            lbOkCount.ForeColor = System.Drawing.Color.Black;
            lbNGCount.ForeColor = System.Drawing.Color.Black;
            lbTotalCount.ForeColor = System.Drawing.Color.Black;

            // 로그 영역
            srcTxtLog.BackColor = System.Drawing.Color.FromArgb(40, 40, 50);
            srcTxtLog.ForeColor = System.Drawing.Color.White;

            // 버튼 스타일 통일화
            foreach (var ctrl in tableLayoutPanel1.Controls)
            {
                if (ctrl is System.Windows.Forms.Button btn)
                {
                    btn.BackColor = mint;
                    btn.ForeColor = System.Drawing.Color.White;
                    btn.FlatStyle = FlatStyle.Flat;
                    btn.FlatAppearance.BorderSize = 0;
                    //btn.Font = new Font("맑은 고딕", 18F, FontStyle.Bold);
                    btn.Region = System.Drawing.Region.FromHrgn(
                        CreateRoundRectRgn(0, 0, btn.Width, btn.Height, 20, 20));

                    btn.MouseEnter += (s, e) => btn.BackColor = ColorTranslator.FromHtml("#00838F");
                    btn.MouseLeave += (s, e) => btn.BackColor = mint;
                }
            }
        }

        [System.Runtime.InteropServices.DllImport("Gdi32.dll", EntryPoint = "CreateRoundRectRgn")]
        private static extern IntPtr CreateRoundRectRgn(
            int nLeftRect, int nTopRect, int nRightRect, int nBottomRect,
            int nWidthEllipse, int nHeightEllipse);
        private void _FrmMain_Load(object sender, EventArgs e)
        {

            Logger.Initialize(srcTxtLog);

            StyleControls();

            GlobalValues.LoadSettingsFromIni();

            // FIO 초기화
            _fio = new ClassFio(GlobalValues.FioPort, 115200);
            if (!_fio.Open())
            {
                Logger.Log($"FIO 포트 열기 실패: {GlobalValues.FioPort}");
            }
            else
            {
                Logger.Log($"FIO 포트 열기 성공: {GlobalValues.FioPort}");
            }

            // Serial Air Pressure 초기화
            SerialAIrPress1 = new ClassSerialGather(GlobalValues.SerialAirPressPort, 9600, 100);
            SerialAIrPress1.Enabled = GlobalValues.SerialAirPressEnabled;
            SerialAIrPress1.DataReceived += SerialAIrPress1_DataReceived;
            if (!SerialAIrPress1.Open())
            {
                Logger.Log($"Serial Air Pressure 포트 열기 실패: {GlobalValues.SerialAirPressPort}");
            }
            else
            {
                if (GlobalValues.SerialAirPressEnabled)
                    Logger.Log($"Serial Air Pressure 포트 열기 성공: {GlobalValues.SerialAirPressPort}");
                else
                    Logger.Log($"Serial Air Pressure 미사용 모드");
            }

            this.BackColor = ColorTranslator.FromHtml("#F2F4F8");
            srcTxtLog.Font = new Font("Consolas", 12F); // 모노스페이스 폰트로 로그 느낌 강조

            GlobalValues.LoadCounts();
            lbOkCount.Text = GlobalValues.OkCount.ToString();
            lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
            lbTotalCount.Text = GlobalValues.TotalCount.ToString();

            tmrWorkTimer = new System.Windows.Forms.Timer();
            tmrWorkTimer.Interval = 100; // 100ms 간격 체크
            tmrWorkTimer.Tick += tmrWorkTimer_Tick;
            tmrWorkTimer.Start();

            InitControl();

            this.FormClosing += _FrmMain_FormClosing;

        }

        private void _FrmMain_FormClosing(object sender, FormClosingEventArgs e)
        {
            if (_fio != null)
            {
                _fio.Close();
                _fio.Dispose();
                _fio = null;
            }

            if (SerialAIrPress1 != null)
            {
                SerialAIrPress1.Close();
                SerialAIrPress1.Dispose();
                SerialAIrPress1 = null;
            }
        }

        private static Mutex mutex;


        public _FrmMain()
        {
            InitializeComponent();

            bool isNewInstance;
            mutex = new Mutex(true, "FtechTestUI", out isNewInstance);
            if (!isNewInstance)
            {
                MessageBox.Show("이미 프로그램이 실행 중입니다.", "중복 실행 방지", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                Environment.Exit(0); // 완전히 종료
            }
            this.AutoScaleMode = AutoScaleMode.Dpi;
        }

        private void RequestResistance(int index)
        {
            if (SerialResists[index]?.IsOpen == true)
            {
                SerialResists[index].Write(":MEAS:RES?\r\n");
                RequestReady_Resists[index] = false;
            }
        }

        private void SerialRetryTimer_Tick(object sender, EventArgs e)
        {
            for (int i = 0; i < SerialResists.Length; i++)
            {
                if (RequestReady_Resists[i])
                {
                    RequestResistance(i);
                }
            }
        }
        private enum WorkState
        {
            Idle = 0,             // 대기 상태
            Start = 1,            // 검사 시작
            Measuring = 2,        // 측정 중
            SaveData = 3,         // 측정 데이터 저장
            ClearSignal = 4       // 신호 클리어 대기
        }

        private WorkState currentState = WorkState.Idle;


        private int wStep = 0;
        private string tmp = "";
        private Stopwatch tmrStopWatch = new Stopwatch();
        private List<double> graphValueList = new List<double>(); // case 12에서 그래프 값 수집용
        private double graphMax = 0.0; // case 12에서 계산된 최대값
        private double graphMin = 0.0; // case 12에서 계산된 최소값
        private double graphAvg = 0.0; // case 12에서 계산된 평균값
        private double graphLast = 0.0; // case 12에서 계산된 평균값
        public void InsertMes(
            decimal relief_min,
            decimal relief_max,
            decimal relief_avg,
            decimal relief_last,
            string relief_decision
        )
        {
            try
            {
                DateTime now = DateTime.Now;
                string work_date = now.ToString("yyyy-MM-dd");
                TimeSpan work_start_time = GlobalValues.WorkStartTime != DateTime.MinValue
                    ? GlobalValues.WorkStartTime.TimeOfDay
                    : now.TimeOfDay;
                TimeSpan work_end_time = now.TimeOfDay;

                using (var conn = new OleDbConnection(GlobalValues.gConString_MES))
                {
                    conn.Open();

                    string query = @"
                INSERT INTO AIR_PUMP_ASSY_340
                (
                    work_date,
                    work_start_time,
                    work_end_time,
                    relief_min,
                    relief_max,
                    relief_avg,
                    relief_last,
                    relief_decision
                )
                VALUES
                (
                    ?, ?, ?, ?, ?, ?, ?, ?
                )";

                    using (var cmd = new OleDbCommand(query, conn))
                    {
                        cmd.Parameters.AddWithValue("@p1", work_date);
                        cmd.Parameters.AddWithValue("@p2", work_start_time.ToString(@"hh\:mm\:ss"));
                        cmd.Parameters.AddWithValue("@p3", work_end_time.ToString(@"hh\:mm\:ss"));
                        cmd.Parameters.AddWithValue("@p4", relief_min);
                        cmd.Parameters.AddWithValue("@p5", relief_max);
                        cmd.Parameters.AddWithValue("@p6", relief_avg);
                        cmd.Parameters.AddWithValue("@p7", relief_last);
                        cmd.Parameters.AddWithValue("@p8", relief_decision ?? (object)DBNull.Value);

                        cmd.ExecuteNonQuery();
                    }
                }

                Logger.Log("MES 데이터 삽입 성공");
            }
            catch (Exception ex)
            {
                Logger.Log("MES 데이터 삽입 오류: " + ex.Message);
            }
        }

        bool LastOk;
        string Decision = "";
        bool FlagButtonRelease;

        private int L_OUT_SIGNAL = 1;
        private int R_OUT_SIGNAL = 0;
        private int L_IN_BUTTON_SIGNAL = 0;
        private int R_IN_BUTTON_SIGNAL = 2;
        private int RESET_BUTTON_SIGNAL = 1;

        private void tmrWorkTimer_Tick(object sender, EventArgs e)
        {
            srcState.Text = currentState.ToString();
            lbBar1.Text = ValAirPress1.ToString() + " bar";
            bool[] fioInputs = _fio.FioInput();
            // 전압 값 실시간 표시 (이벤트로도 업데이트되지만, 타이머에서도 업데이트)

            if (fioInputs[RESET_BUTTON_SIGNAL] == true && wStep != 0)
            {
                InitControl();
                _fio.Fio_Do_Off(L_OUT_SIGNAL);
                _fio.Fio_Do_Off(R_OUT_SIGNAL);
                wStep = 0;
            }
            switch (wStep)
            {

                case 0:

                    if (fioInputs[L_IN_BUTTON_SIGNAL] == true)
                    {
                        InitControl();
                        GlobalValues.WorkStartTime = DateTime.Now; // 작업 시작 시간 저장
                        FlagButtonRelease = false;
                        wStep = 10;
                    }
                    else if (fioInputs[R_IN_BUTTON_SIGNAL] == true)
                    {
                        InitControl();
                        GlobalValues.WorkStartTime = DateTime.Now; // 작업 시작 시간 저장
                        FlagButtonRelease = false;
                        wStep = 20;
                    }
                    break;

                case 10:

                    _fio.Fio_Do_On(L_OUT_SIGNAL);
                    tmrStopWatch.Restart();
                    wStep = 11;
                    break;

                case 11:
                    if (tmrStopWatch.Elapsed.TotalSeconds > 1)
                    {
                        graphValueList.Clear(); // case 12 시작 전 리스트 초기화
                        wStep = 12;
                    }
                    break;

                case 12:

                    if (fioInputs[L_IN_BUTTON_SIGNAL] == false)
                    {
                        FlagButtonRelease = true;
                    }
                    double t = tmrStopWatch.Elapsed.TotalSeconds;
                    ClassZedGraph.DrawGraph(GraphL, ValAirPress1, t);

                    // 그래프 값 수집 (fioInputs[0] == true 되기 전까지)
                    graphValueList.Add(ValAirPress1);

                    if (fioInputs[L_IN_BUTTON_SIGNAL] == true && FlagButtonRelease == true)
                    {
                        _fio.Fio_Do_Off(L_OUT_SIGNAL);
                        // 그래프 값의 최대, 최소, 평균 계산하여 필드 변수에 저장
                        graphMax = graphValueList.Count > 0 ? graphValueList.Max() : 0.0;
                        graphMin = graphValueList.Count > 0 ? graphValueList.Min() : 0.0;
                        graphAvg = graphValueList.Count > 0 ? graphValueList.Average() : 0.0;
                        graphLast = ValAirPress1;
                        wStep = 13;
                    }
                    break;

                case 13:
                    // 값 표시
                    srclbValMinL.Text = $"{graphMin:F4}";
                    srclbValMaxL.Text = $"{graphMax:F4}";
                    srclbValAvrL.Text = $"{graphAvg:F4}";
                    srclbValLastL.Text = $"{graphLast:F4}";

                    // 판정: Avr 값이 범위 내에 있는지 확인
                    LastOk = (graphLast >= GlobalValues._1cellAir_Max_Min) && (graphLast <= GlobalValues._1cellAir_Max_Max);
                    srclbDecMaxL.Text = LastOk ? "OK" : "NG";
                    srclbDecMaxL.ForeColor = LastOk ? Color.Green : Color.Red;
                    wStep = 14;
                    break;

                case 14:                    
                    Decision = LastOk ? "OK" : "NG";
                    InsertMes(
                        (decimal)graphMin,
                        (decimal)graphMax,
                        (decimal)graphAvg,
                        (decimal)graphLast,
                        Decision
                    );

                    wStep = 0;
                    break;

                case 20:

                    _fio.Fio_Do_On(R_OUT_SIGNAL);
                    tmrStopWatch.Restart();
                    wStep = 21;
                    break;

                case 21:
                    if (tmrStopWatch.Elapsed.TotalSeconds > 1)
                    {
                        graphValueList.Clear(); // case 22 시작 전 리스트 초기화
                        wStep = 22;
                    }
                    break;

                case 22:
                    if (fioInputs[R_IN_BUTTON_SIGNAL] == false)
                    {
                        FlagButtonRelease = true;
                    }

                    double tR = tmrStopWatch.Elapsed.TotalSeconds;
                    ClassZedGraph.DrawGraph(GraphR, ValAirPress1, tR);

                    // 그래프 값 수집 (fioInputs[2] == true 되기 전까지)
                    graphValueList.Add(ValAirPress1);

                    if (fioInputs[R_IN_BUTTON_SIGNAL] == true && FlagButtonRelease == true)
                    {
                        _fio.Fio_Do_Off(R_OUT_SIGNAL);
                        // 그래프 값의 최대, 최소, 평균 계산하여 필드 변수에 저장
                        graphMax = graphValueList.Count > 0 ? graphValueList.Max() : 0.0;
                        graphMin = graphValueList.Count > 0 ? graphValueList.Min() : 0.0;
                        graphAvg = graphValueList.Count > 0 ? graphValueList.Average() : 0.0;
                        graphLast = ValAirPress1;
                        wStep = 23;
                    }
                    break;

                case 23:
                    // 값 표시
                    srclbValMinR.Text = $"{graphMin:F4}";
                    srclbValMaxR.Text = $"{graphMax:F4}";
                    srclbValAvrR.Text = $"{graphAvg:F4}";
                    srclbValLastR.Text = $"{graphLast:F4}";

                    // 판정: Avr 값이 범위 내에 있는지 확인
