                    srclbDecMaxR.ForeColor = LastOk ? Color.Green : Color.Red;
                    wStep = 24;
                    break;

                case 24:                    
                    Decision = LastOk ? "OK" : "NG";
                    InsertMes(
                        (decimal)graphMin,
                        (decimal)graphMax,
                        (decimal)graphAvg,
                        (decimal)graphLast,
                        Decision
