        public void BeginMeasurement()
        {
            try
            {
                // 기존 인스턴스가 있으면 해제
                if (voltageMonitor != null)
                {
                    voltageMonitor.Stop();
                    voltageMonitor.Dispose();
                    voltageMonitor = null;
                }

                // DAQ 채널 설정 (config.ini에서 읽거나 자동 탐지)
                IniFile ini = new IniFile("config.ini");
                string channel0 = ini.ReadValue("DAQ", "Channel0");
                string channel1 = ini.ReadValue("DAQ", "Channel1");

                // 연결된 DAQ 장치 자동 탐지 (Dev1부터 Dev10까지 시도)
                string deviceName = "Dev1"; // 기본값
                if (string.IsNullOrWhiteSpace(channel0))
                {
                    try
                    {
                        // 기존 Task 정리 (혹시 남아있을 수 있음)
                        try
                        {
                            using (Task cleanupTask = new Task("DaqTask"))
                            {
                                cleanupTask.Dispose();
                            }
                        }
                        catch { }

                        for (int i = 1; i <= 10; i++)
                        {
                            string testDevice = $"Dev{i}";
                            string testChannel = $"{testDevice}/ai0";
                            Task testTask = null;
                            try
                            {
                                testTask = new Task($"AutoDetectTask_{i}");
                                testTask.AIChannels.CreateVoltageChannel(
                                    testChannel, "Test", AITerminalConfiguration.Differential, -10, 10, AIVoltageUnits.Volts);
                                deviceName = testDevice;
                                Logger.Log($"DAQ 장치 자동 탐지: {deviceName}");
                                testTask.Stop();
                                testTask.Dispose();
                                testTask = null;
                                Thread.Sleep(200); // Task 해제 대기
                                break;
                            }
                            catch
                            {
                                // 이 장치는 없음, 다음 장치 시도
                                if (testTask != null)
                                {
                                    try { testTask.Dispose(); } catch { }
                                }
                                continue;
                            }
                        }
                    }
                    catch (Exception ex)
                    {
                        Logger.Log($"DAQ 장치 탐지 실패: {ex.Message}, 기본값 Dev1 사용");
                    }
                    channel0 = $"{deviceName}/ai0";
                }
                if (string.IsNullOrWhiteSpace(channel1))
                {
                    // channel0에서 장치명 추출
                    if (channel0.Contains("/"))
                    {
                        deviceName = channel0.Split('/')[0];
                    }
                    channel1 = $"{deviceName}/ai1";
                }

                string[] channels = { channel0, channel1 };

                // VoltageMonitor 생성
                voltageMonitor = new VoltageMonitor(
                    physicalChannels: channels,
                    sampleRate_Hz: 1000,
                    samplesPerRead: 10,
                    voltMin: 0,
                    voltMax: 10.0,
                    termCfg: AITerminalConfiguration.Differential,
                    logger: Logger.Log
                );

                // 측정 시작
                voltageMonitor.Start();

                Logger.Log($"전압 측정 시작: 채널0={channel0}, 채널1={channel1}");
            }
            catch (Exception ex)
            {
                Logger.Log($"전압 측정 시작 실패: {ex.Message}");
            }
        }
        public void EndMeasurement()
        {
            try
            {
                if (voltageMonitor != null)
                {
                    // 이벤트 구독 해제

                    // 최종 측정값 로그 출력
                    Logger.Log($"측정 종료 - Volt_0: {voltageMonitor.Volt_0:F3}V, Volt_1: {voltageMonitor.Volt_1:F3}V");

                    voltageMonitor.Stop();
                    voltageMonitor.Dispose();
                    voltageMonitor = null;

                    Logger.Log("전압 측정 종료");
                }
            }
            catch (Exception ex)
            {
                Logger.Log($"전압 측정 종료 실패: {ex.Message}");
            }
        }

        // Serial Air Pressure 게더링 이벤트 핸들러
        private double ValAirPress1;
        private void SerialAIrPress1_DataReceived(string data)
        {
            try
            {
                // 이미 쉼표로 분리된 앞부분만 전달됨
                //Logger.Log($"Air Pressure 수신: {data}");

                // 압력 값 파싱 및 처리
                if (double.TryParse(data, out double pressure))
                {
                    // pressure 변수에 압력 값 저장 (필요시 전역 변수나 프로퍼티에 저장)
                    ValAirPress1 = pressure;
                }
            }
            catch (Exception ex)
            {
                Logger.Log($"Air Pressure 데이터 처리 오류: {ex.Message}");
            }
        }

        private void button1_Click(object sender, EventArgs e)
        {
            InsertMes(1, 2, 3, 4, "OK");
        }
    }
}

