using System;
using System.IO.Ports;
using System.Text;
using System.Threading;
using ResisterTest.Managers;

public class ClassSerialGather : IDisposable
{
    private SerialPort _serialPort;
    private Thread _readThread;
    private Timer _pollTimer;
    private bool _isRunning;
    private StringBuilder _recvBuffer;
    private readonly object _lockObject = new object();

    //50 52 45 53 53 55 52 45 3F 0D 0A
    // Send 프로토콜: 50 52 45 53 53 55 52 45 3F 0D 0A = "PRESSURE?\r\n"
    private readonly byte[] _sendProtocol = { 0x50, 0x52, 0x45, 0x53, 0x53, 0x55, 0x52, 0x45, 0x3F, 0x0D, 0x0A };

    // Recv 종료 시퀀스: 0D 0A = "\r\n"
    private readonly byte[] _recvEndSequence = { 0x0D, 0x0A };

    private int _pollingInterval = 200; // ms

    // 로그 출력 플래그
    public bool EnableLog { get; set; } = false;

    // 사용/미사용 플래그
    public bool Enabled { get; set; } = false;

    // 수신 데이터 프로퍼티
    public string ReceivedData { get; private set; } = string.Empty;

    // 연결 상태
    public bool IsOpen => _serialPort != null && _serialPort.IsOpen;

    // 데이터 수신 이벤트
    public event Action<string> DataReceived;

    public ClassSerialGather(string portName, int baudRate = 9600, int pollingInterval = 200)
    {
        _serialPort = new SerialPort(portName, baudRate, Parity.None, 8, StopBits.One)
        {
            ReadTimeout = 1000,
            WriteTimeout = 1000
        };

        _recvBuffer = new StringBuilder();
        _pollingInterval = pollingInterval;
    }

    public bool Open()
    {
        // 미사용 모드면 실제로 열지 않고 성공 반환
        if (!Enabled)
        {
            Log($"Serial 포트 미사용 모드: {_serialPort.PortName}");
            return true;
        }

        try
        {
            if (_serialPort.IsOpen)
                return true;

            _serialPort.Open();

            if (_serialPort.IsOpen)
            {
                _isRunning = true;

                // 읽기 스레드 시작
                _readThread = new Thread(ReadThreadTask)
                {
                    IsBackground = true
                };
                _readThread.Start();

                // 폴링 타이머 시작
                _pollTimer = new Timer(PollTimerCallback, null, 0, _pollingInterval);

                Log($"Serial 포트 열림: {_serialPort.PortName}, BaudRate: {_serialPort.BaudRate}, Polling: {_pollingInterval}ms");
                return true;
            }
        }
        catch (Exception ex)
        {
            Log($"Serial 포트 열기 실패: {ex.Message}");
        }
        return false;
    }

    public void Close()
    {
        _isRunning = false;

        // 타이머 정지
        if (_pollTimer != null)
        {
            _pollTimer.Dispose();
            _pollTimer = null;
        }

        // 읽기 스레드 종료
        if (_readThread != null && _readThread.IsAlive)
        {
            _readThread.Join(1000);
        }

        // 시리얼 포트 닫기
        if (_serialPort != null && _serialPort.IsOpen)
        {
            _serialPort.Close();
            Log("Serial 포트 닫힘");
        }
    }

    private void PollTimerCallback(object state)
    {
        if (!Enabled || !_isRunning || _serialPort == null || !_serialPort.IsOpen)
            return;

        try
        {
            _serialPort.Write(_sendProtocol, 0, _sendProtocol.Length);
            Log($"Send: {BitConverter.ToString(_sendProtocol)}");
        }
        catch (Exception ex)
        {
            Log($"Send 오류: {ex.Message}");
        }
    }

    private void ReadThreadTask()
    {
        byte[] buffer = new byte[1024];

        while (Enabled && _isRunning && _serialPort != null && _serialPort.IsOpen)
        {
            try
            {
                if (_serialPort.BytesToRead > 0)
                {
                    int bytesRead = _serialPort.Read(buffer, 0, Math.Min(buffer.Length, _serialPort.BytesToRead));

                    if (bytesRead > 0)
                    {
                        lock (_lockObject)
                        {
                            // 수신 데이터를 버퍼에 추가
                            for (int i = 0; i < bytesRead; i++)
                            {
                                _recvBuffer.Append((char)buffer[i]);
                            }

                            // 종료 시퀀스(0D 0A) 확인
                            string data = _recvBuffer.ToString();
                            int endIndex = FindEndSequence(data);

                            if (endIndex >= 0)
                            {
                                // 종료 시퀀스까지의 데이터 추출
                                string received = data.Substring(0, endIndex);

                                // 쉼표(2C)로 구분해서 앞부분만 추출
                                string[] parts = received.Split(',');
                                string pressureValue = parts.Length > 0 ? parts[0].Trim() : received;

                                ReceivedData = pressureValue;

                                // 이벤트 발생 (앞부분만 전달)
                                DataReceived?.Invoke(pressureValue);

                                Log($"Recv: {received} → 파싱: {pressureValue}");

                                // 버퍼 정리 (종료 시퀀스 이후 데이터는 다음 패킷으로)
                                if (endIndex + 2 < data.Length)
                                {
                                    _recvBuffer.Clear();
                                    _recvBuffer.Append(data.Substring(endIndex + 2));
                                }
                                else
                                {
                                    _recvBuffer.Clear();
                                }
                            }
                        }
                    }
                }
            }
            catch (TimeoutException)
            {
                // 타임아웃은 정상 동작
            }
            catch (Exception ex)
            {
                Log($"Serial 읽기 오류: {ex.Message}");
            }

            Thread.Sleep(10);
        }
    }

    private int FindEndSequence(string data)
    {
        // 종료 시퀀스 0D 0A (\r\n) 찾기
        for (int i = 0; i < data.Length - 1; i++)
        {
            if (data[i] == '\r' && data[i + 1] == '\n')
            {
                return i;
            }
        }
        return -1;
    }

    private void Log(string message)
    {
        if (EnableLog)
        {
            Logger.Log($"[SerialGather] {message}");
        }
    }

    public void Dispose()
    {
        Close();

        if (_serialPort != null)
        {
            _serialPort.Dispose();
            _serialPort = null;
        }
    }
}

