        // 타이머 정지
        if (_pollTimer != null)
        {
            _pollTimer.Dispose();
            _pollTimer = null;
        }

        // 읽기 스레드 종료
        if (_readThread != null && _readThread.IsAlive)
        {
            _readThread.Join(1000);
        }

        // 시리얼 포트 닫기
        if (_serialPort != null && _serialPort.IsOpen)
        {
            _serialPort.Close();
            Log("Serial 포트 닫힘");
        }
    }

    private void PollTimerCallback(object state)
    {
        if (!Enabled || !_isRunning || _serialPort == null || !_serialPort.IsOpen)
            return;

        // 이전 폴링이 아직 처리 중이면 스킵 (중첩 방지)
        if (Interlocked.CompareExchange(ref _pollBusy, 1, 0) != 0)
            return;

        try
        {
            _serialPort.Write(_sendProtocol, 0, _sendProtocol.Length);
            Log($"Send: {BitConverter.ToString(_sendProtocol)}");
        }
        catch (Exception ex)
        {
            Log($"Send 오류: {ex.Message}");
        }
    }

    private void ReadThreadTask()
    {
        byte[] buffer = new byte[1024];

        while (Enabled && _isRunning && _serialPort != null && _serialPort.IsOpen)
        {
            try
            {
                if (_serialPort.BytesToRead > 0)
                {
                    int bytesRead = _serialPort.Read(buffer, 0, Math.Min(buffer.Length, _serialPort.BytesToRead));

                    if (bytesRead > 0)
                    {
                        lock (_lockObject)
                        {
                            // 버퍼 오버플로우 방지: 최대 크기 초과 시 강제 정리
                            if (_recvBuffer.Length > MAX_BUFFER_SIZE)
                            {
                                Log($"버퍼 오버플로우 감지 ({_recvBuffer.Length}bytes), 버퍼 초기화");
                                _recvBuffer.Clear();
                            }

                            // 수신 데이터를 버퍼에 추가
                            for (int i = 0; i < bytesRead; i++)
                            {
                                _recvBuffer.Append((char)buffer[i]);
                            }

                            // 종료 시퀀스(0D 0A) 반복 처리 (버퍼에 여러 패킷이 쌓여있을 수 있음)
                            ProcessBuffer();
                        }
                    }
                }
            }
            catch (TimeoutException)
            {
                // 타임아웃은 정상 동작
            }
            catch (Exception ex)
            {
                Log($"Serial 읽기 오류: {ex.Message}");
            }

            Thread.Sleep(10);
        }
    }

    // 버퍼에서 완성된 패킷을 모두 꺼내서 처리
    private void ProcessBuffer()
    {
        string data = _recvBuffer.ToString();
        int endIndex;

        while ((endIndex = data.IndexOf("\r\n", StringComparison.Ordinal)) >= 0)
        {
            // 종료 시퀀스까지의 데이터 추출
            string received = data.Substring(0, endIndex);

            // 쉼표(2C)로 구분해서 앞부분만 추출
            int commaIdx = received.IndexOf(',');
            string pressureValue = commaIdx >= 0 ? received.Substring(0, commaIdx).Trim() : received.Trim();

            if (pressureValue.Length > 0)
            {
                ReceivedData = pressureValue;
                DataReceived?.Invoke(pressureValue);
                Log($"Recv: {received} → 파싱: {pressureValue}");
            }

            // 다음 패킷으로 이동
            data = data.Substring(endIndex + 2);

            // 폴링 완료 플래그 해제 → 다음 PRESSURE? 전송 가능
            Interlocked.Exchange(ref _pollBusy, 0);
        }

        // 남은 데이터를 버퍼에 보존
        _recvBuffer.Clear();
        if (data.Length > 0)
            _recvBuffer.Append(data);
    }

    private int FindEndSequence(string data)
    {
        // 종료 시퀀스 0D 0A (\r\n) 찾기
        for (int i = 0; i < data.Length - 1; i++)
        {
            if (data[i] == '\r' && data[i + 1] == '\n')
            {
                return i;
            }
        }
        return -1;
    }

    private void Log(string message)
    {
        if (EnableLog)
        {
            Logger.Log($"[SerialGather] {message}");
        }
    }

    public void Dispose()
    {
        Close();

        if (_serialPort != null)
        {
            _serialPort.Dispose();
            _serialPort = null;
        }
    }
}

